import React from "react";

export default function ({ data = [] }) {

  const totalsByProduct = data.reduce((acc, obj) => {
    obj.steps?.forEach((step) => {
      step.consumptions?.forEach((consumption) => {
        const code = consumption.productPacking.code;
        const qty = consumption.quantity || 0;

        // 3. Accumulate sum grouped by code
        if (!acc[code]) {
          acc[code] = {
            description: [
              consumption.productPacking.product.description,
              consumption.productPacking.complement,
              consumption.productPacking.variant?.description
            ].filter(Boolean).join(", "),
            unit: consumption.productPacking.product.unit,
            quantity: 0,
          };
        }
        acc[code].quantity += qty;
      });
    });
    return acc;
  }, {});

  return (
    <div className="report-wrapper">
      {/* Impresso 1, Ordens de produção */}
      <div className="report-container">
        <header>
          <h1>Ordens de Produção</h1>
        </header>
        <main>
          <div className="content">
            {data.map((obj) => (
              <>
                <div class="flex h full gap padding panel">
                  <div>
                    <strong>Ordem de produção</strong><br />
                    {obj.id}
                  </div>
                  <div>
                    <strong>Cliente</strong><br />
                    {obj.person.name}
                  </div>
                  <div>
                    <strong>Data pedido</strong><br />
                    {obj.date ? date(obj.date) : "-"}
                  </div>
                  <div>
                    <strong>Data entrega</strong><br />
                    {obj.availabilityDate ? date(obj.availabilityDate) : "-"}
                  </div>
                  <div>
                    <strong>Data cliente</strong><br />
                    {obj.availabilityDate ? date(obj.availabilityDate) : "-"}
                  </div>
                  <div>
                    <strong>Pedidos</strong><br />
                    {obj.code}
                  </div>
                </div>
                {obj.steps?.map((step, index) => (
                  <React.Fragment key={index}>
                    <div class="flex h">
                      <div class="flex v gap padding center" style={{ flex: "1" }}>
                        <div class="xxl">{obj.code}</div>
                        <div>{step.productPacking.code}</div>
                        <div><span className="xxl">{step.quantity}</span>&nbsp;{step.productPacking.product.unit.code}</div>
                      </div>

                      <div class="flex v gap padding flex-1" style={{ flex: "2" }}>
                        <table>
                          <thead>
                            <tr>
                              <th>Código do Produto</th>
                              <th>Descrição do Produto</th>
                              <th class="number">Quantidade</th>
                            </tr>
                          </thead>
                          <tbody>
                            {step.consumptions?.map((consumption, index) => (
                              <tr key={index}>
                                <td>{consumption.productPacking.code}</td>
                                <td>{[
                                  consumption.productPacking.product.description,
                                  consumption.productPacking.complement,
                                  consumption.productPacking.variant?.description
                                ].filter(Boolean).join(", ")}</td>
                                <td className="number">
                                  {number(consumption.quantity)}&nbsp;{consumption.productPacking.product.unit.code}
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>

                    {/* <li key={index}>
                    Etapa {step.id}
                    <ul>
                      {step.productions?.map((production, index) => (
                        <li key={index}>Produção: {production.productPacking.code}, quantidade: {number(production.quantity)},
                        </li>
                      ))}
                      {step.consumptions?.map((consumption, index) => (
                        <li key={index}>Consumo: {consumption.productPacking.code}, quantidade: {number(consumption.quantity)},
                        </li>
                      ))}
                    </ul>
                  </li> */}
                  </React.Fragment>
                ))}
              </>
            ))}
          </div>
        </main>
      </div>

      {/* Impresso 2,  */}
      <div className="report-container">
        <header>
          <h1>Consumo de materiais por lote de produção</h1>
          <section className="parameters">
            <div>
              <dl>
                <dt>Cliente</dt>
                <dd>{data[0].person?.name}</dd>
              </dl>
            </div>
            <div>
              <dl>
                <dt>Previsão de entrega</dt>
                <dd>{date(data[0].availabilityDate)}</dd>
              </dl>
            </div>
            <div>
              <dl>
                <dt>Pedido</dt>
                <dd>{data[0].properties?.sale_id}</dd>
              </dl>
            </div>
          </section>
        </header>
        <main>
          <div className="content">
            <table style={{ width: "100%" }}>
              <thead>
                <th>Código</th>
                <th>Descrição</th>
                <th className="number">Quantidade</th>
              </thead>
              <tbody>
                {Object
                  .entries(totalsByProduct)
                  .sort(([codeA], [codeB]) => codeA.localeCompare(codeB))
                  .map(([code, total]) => (
                    <tr key={code}>
                      <td>{code}</td>
                      <td>{total.description}</td>
                      <td className="number">{`${number(total.quantity)} ${total.unit.code}`}</td>
                    </tr>
                  ))}
              </tbody>
            </table>
          </div>
        </main>
      </div>

      {/* Impresso 3, Itens a produzir */}
      <div className="report-container">
        <header>
          <h1>Itens a produzir</h1>
        </header>
        <div className="grid" style={{ gridTemplateColumns: "repeat(4, 1fr)", gap: "var(--gap)" }}>
          {data.map((obj) => (
            <div key={obj.id} className="card flex v align-center justify-center">
              {obj.steps?.map((step, index) => (
                <React.Fragment key={index}>
                  {step.productions?.map((production, index) => (
                    <React.Fragment key={index}>
                      <p>{obj.properties.sale_id}</p>
                      <p key={index}>{production.productPacking.code}</p>
                      <p key={index}>{production.productPacking.variant?.description}</p>
                    </React.Fragment>
                  ))}
                </React.Fragment>
              ))}
            </div>
          ))}
        </div>
      </div>

    </div>
  );
};

function date(value) {
  return new Intl.DateTimeFormat("pt-BR").format(new Date(value));
}

function number(value) {
  return new Intl.NumberFormat("pt-BR", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
}

function text(value) {
  return <strong>{value?.toUpperCase()}</strong>;
}

styles:
@font-face {
  font-family: "AnekLatin";
  src: url("https://s3.sa-east-1.amazonaws.com/zenerp.app.br/assets/fonts/AnekLatin.ttf") format("truetype");
  font-weight: normal;
  font-style: normal;
}
html,
body {
  margin: 0;
  padding: 0;
}

.report-wrapper {
  --border-radius: 0.2em;
  --color-border: rgba(0, 0, 0, 0.1);
  --color-shadow: rgba(0, 0, 0, 0.1);
  --gap: 0.5rem;
  --padding: 0.35rem;
  font-family: "AnekLatin", "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  font-size: 11pt;
}
.report-wrapper dl {
  display: block;
  margin: 0;
  padding: 0;
}
@media screen {
  .report-wrapper {
    padding: 1rem;
  }
}
.report-wrapper .report-container {
  position: relative;
  page-break-after: always;
  break-after: page;
  background-color: white;
}
.report-wrapper .report-container .stamp {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-45deg);
  font-size: 300%;
  opacity: 0.3;
  color: red;
}
.report-wrapper .report-container > header {
  display: flex;
  flex-direction: column;
  gap: var(--gap);
  border-bottom: 3px solid #000;
  padding-bottom: 1rem;
  margin-bottom: 1rem;
}
.report-wrapper .report-container > header .brand {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
}
.report-wrapper .report-container > header h1 {
  margin: 0;
  font-size: 20pt;
}
.report-wrapper .report-container > header section.parameters {
  display: flex;
  gap: var(--gap);
}
.report-wrapper .report-container > header dl {
  display: flex;
  gap: var(--gap);
  margin: 0;
}
.report-wrapper .report-container > header dl div {
  flex: 1;
  border: 1px solid var(--color-border);
  border-radius: var(--border-radius);
  padding: var(--padding);
}
.report-wrapper .report-container > header dl div dt {
  font-size: 8pt;
  color: gray;
  text-transform: uppercase;
  font-weight: bold;
}
.report-wrapper .report-container > header dl div dd {
  margin: 0;
}
.report-wrapper .report-container > main .kpi-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1rem;
  margin-bottom: 2rem;
}
.report-wrapper .report-container > main .kpi-grid dl {
  border: 1px solid var(--color-border);
  padding: 1rem;
  background: #fdfdfd;
  display: flex;
  justify-content: space-between;
}
.report-wrapper .report-container > main .kpi-grid dl dt {
  font-size: 9pt;
  color: gray;
}
.report-wrapper .report-container > main .kpi-grid dl dd {
  margin: 0;
  font-size: 16pt;
  font-weight: bold;
}
.report-wrapper .report-container > main .kpi-grid dl .kpi-trend {
  font-size: 8pt;
  align-self: flex-end;
}
.report-wrapper .report-container > main section {
  margin-top: 1.5rem;
}
.report-wrapper .report-container > main section section {
  padding-left: 1rem;
}
.report-wrapper .report-container > main section > header {
  font-weight: bold;
  border-bottom: 1px solid var(--color-border);
  margin-bottom: 0.5rem;
}
.report-wrapper .report-container > main section > footer {
  font-size: 9pt;
  font-style: italic;
  color: gray;
  padding-top: 5px;
}
.report-wrapper .report-container > main .content table:not(.custom) {
  width: 100%;
  border-collapse: collapse;
}
.report-wrapper .report-container > main .content table:not(.custom) th {
  text-align: left;
}
.report-wrapper .report-container > footer {
  margin-top: 4rem;
  border-top: 2px solid #000;
  padding-top: 1rem;
}
.report-wrapper .report-container > footer .signature-block {
  display: flex;
  justify-content: space-between;
  margin-top: 2rem;
}
.report-wrapper .report-container > footer dl {
  display: flex;
  gap: var(--gap);
  margin: 0;
}
.report-wrapper .report-container > footer dl div {
  flex: 1;
  border: 1px solid var(--color-border);
  border-radius: var(--border-radius);
  padding: var(--padding);
}
.report-wrapper .report-container > footer dl div dt {
  font-size: 8pt;
  color: gray;
  text-transform: uppercase;
  font-weight: bold;
}
.report-wrapper .report-container > footer dl div dd {
  margin: 0;
}
.report-wrapper .flex {
  display: flex;
}
.report-wrapper .flex.h {
  flex-direction: row;
}
.report-wrapper .flex.v {
  flex-direction: column;
}
.report-wrapper .flex.align-center {
  align-items: center;
}
.report-wrapper .flex.justify-center {
  justify-content: center;
}
.report-wrapper .flex.justify-space-around {
  justify-content: space-around;
}
.report-wrapper .flex.justify-space-between {
  justify-content: space-between;
}
.report-wrapper .flex.gap {
  gap: 0.5rem;
}
.report-wrapper .flex .flex-1 {
  flex: 1;
}
.report-wrapper .grid {
  display: grid;
}
.report-wrapper .text-center {
  text-align: center;
}
.report-wrapper .text-right,
.report-wrapper .number {
  text-align: right !important;
}
.report-wrapper .date {
  font-variant-numeric: tabular-nums;
}
.report-wrapper .number {
  font-variant-numeric: tabular-nums;
}
.report-wrapper .text-success {
  color: green;
}
.report-wrapper .text-danger {
  color: red;
}
.report-wrapper pre {
  font-family: "AnekLatin", "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  white-space: pre-wrap;
  word-wrap: break-word;
  overflow-wrap: break-word;
  margin: 0;
}
.card {
  border: 1px solid black;
  border-radius: var(--border-radius);
  padding: var(--gap);
}

.padding {
  padding: 0.5rem;
}

.center {
  align-items: center;
  justify-content: center;
}

.flex-1 {
  flex: 1 1 auto;
}

.flex.h > * {
  flex: 1 1 auto;
}

.flex.h.full {
  width: 100%;
}

.panel {
  border-radius: 0.2rem;
  padding: 0.5rem;
  background-color: lightgray;
  border: 1px solid gray;
}

.xxl {
  font-size: 2rem;
  font-weight: bold;
}

.xx {
  background-color: red;
}

th {
  text-align: left;
}

.number {
  text-align: right;
}
